from sys import stdin

def count_distinct_words(s):
    n = len(s)
    cnt = [0] * 26
    for c in s:
        cnt[ord(c) - ord('a')] += 1
    res = 0
    for c in s:
        cnt[ord(c) - ord('a')] -= 1
        for i in range(26):
            if cnt[i] > 0:
                res += 1
        cnt[ord(c) - ord('a')] += 1
    return res

s = stdin.readline().strip()
print(count_distinct_words(s))
